class Solution(object):
    def checkPrimeFrequency(self, nums):
        from collections import Counter
        def is_prime(n):
            if n < 2: return False
            for i in range(2, int(n**0.5) + 1):
                if n % i == 0: return False
            return True
        freq = Counter(nums)
        return any(is_prime(v) for v in freq.values())
